@strawberry.type
class Review:
    id: strawberry.ID
    rating: int
    comment: Optional[str]


@strawberry.type
class Seller:
    id: strawberry.ID
    name: str
    url: Optional[str]


@strawberry.type
class Category:
    id: strawberry.ID
    name: str


@strawberry.type
class Image:
    id: strawberry.ID
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: strawberry.ID
    name: str
    description: Optional[str]

    @strawberry.field
    def reviews(self, info: Info) -> List[Review]:
        return [Review(id=r.id, rating=r.rating, comment=r.comment) for r in self._model.reviews]

    @strawberry.field
    def sellers(self, info: Info) -> List[Seller]:
        return [Seller(id=s.id, name=s.name, url=s.url) for s in self._model.sellers]

    @strawberry.field
    def categories(self, info: Info) -> List[Category]:
        return [Category(id=c.id, name=c.name) for c in self._model.categories]

    @strawberry.field
    def images(self, info: Info) -> List[Image]:
        return [Image(id=i.id, url=i.url, alt_text=i.alt_text) for i in self._model.images]

    @classmethod
    def from_model(cls, model: ProductModel) -> "Product":
        obj = cls(id=model.id, name=model.name, description=model.description)
        obj._model = model
        return obj


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info: Info) -> List[Product]:
        db: SASession = info.context["db"]
        models = (
            db.query(ProductModel)
            .all()
        )
        return [Product.from_model(m) for m in models]

    @strawberry.field
    def product(self, info: Info, id: strawberry.ID) -> Optional[Product]:
        db: SASession = info.context["db"]
        model = db.query(ProductModel).filter(ProductModel.id == str(id)).first()
        return Product.from_model(model) if model else None


schema = strawberry.Schema(query=Query)

app = FastAPI()


def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()


async def get_context():
    db = SessionLocal()
    try:
        yield {"db": db}
    finally:
        db.close()


graphql_app = GraphQLRouter(schema, context_getter=get_context)
app.include_router(graphql_app, prefix="/graphql")


@app.get("/")
def root():
    return {"message": "GraphQL API running at /graphql"}


